function generateCodingQuestions(topics: string[], langKey: "web" | "java" | "python" | "datascience" | "dsa", baseId: number) {
  return topics.map((title, idx) => {
    const qId = baseId + idx;
    let initialCode = "";
    let sampleInput = "10";
    let sampleOutput = "20";

    if (langKey === "web") {
      const funcName = "run" + title.replace(/[^a-zA-Z0-9]/g, "");
      initialCode = `function ${funcName}() {\n  // Implement ${title} logic here\n  \n}\nconsole.log(${funcName}.toString());`;
      sampleInput = "()";
      sampleOutput = `"${title} Complete"`;
    } else if (langKey === "java") {
      initialCode = `import java.util.*;\n\npublic class Main {\n    public static void main(String[] args) {\n        Scanner sc = new Scanner(System.in);\n        // Implement solution logic here\n        \n    }\n}`;
      sampleInput = "10";
      sampleOutput = "20";
    } else if (langKey === "python") {
      initialCode = `import sys\n\ndef process():\n    # Read input from sys.stdin and implement solution logic here\n    pass\n\nif __name__ == '__main__':\n    process()`;
      sampleInput = "15";
      sampleOutput = "30";
    } else if (langKey === "datascience") {
      initialCode = `import sys\n\ndef analyze():\n    # Read input from sys.stdin and implement data analysis logic here\n    pass\n\nif __name__ == '__main__':\n    analyze()`;
      sampleInput = "10.5 20.5";
      sampleOutput = "Result: 31.0";
    } else { // dsa
      initialCode = `#include <bits/stdc++.h>\nusing namespace std;\n\nint solve(int n) {\n    // Implement solution logic here\n    return 0;\n}\n\nint main() {\n    int n;\n    if (cin >> n) {\n        cout << solve(n);\n    }\n    return 0;\n}`;
      sampleInput = "25";
      sampleOutput = "50";
    }

    const testInput1 = langKey === "web" ? "()" : (langKey === "datascience" ? "10.5 20.5" : (langKey === "python" ? "15" : (langKey === "java" ? "10" : "25")));
    const testExpected1 = langKey === "web" ? "CONTAINS:Complete" : (langKey === "datascience" ? "Result: 31.0" : (langKey === "python" ? "30" : (langKey === "java" ? "20" : "50")));

    const testInput2 = langKey === "web" ? "()" : (langKey === "datascience" ? "5.0 5.0" : "5");
    const testExpected2 = langKey === "web" ? "CONTAINS:function" : (langKey === "datascience" ? "Result: 10.0" : "10");

    const testInput3 = langKey === "web" ? "()" : (langKey === "datascience" ? "100.0" : "100");
    const testExpected3 = langKey === "web" ? "CONTAINS:return" : (langKey === "datascience" ? "Result: 100.0" : "200");

    const testInput4 = langKey === "web" ? "()" : (langKey === "datascience" ? "0.0" : "0");
    const testExpected4 = langKey === "web" ? "CONTAINS:{" : (langKey === "datascience" ? "Result: 0.0" : "0");

    const testInput5 = langKey === "web" ? "()" : (langKey === "datascience" ? "1.5 2.5" : "50");
    const testExpected5 = langKey === "web" ? "CONTAINS:}" : (langKey === "datascience" ? "Result: 4.0" : "100");

    const testInput6 = langKey === "web" ? "()" : (langKey === "datascience" ? "50.0 50.0" : "500");
    const testExpected6 = langKey === "web" ? "CONTAINS:Complete" : (langKey === "datascience" ? "Result: 100.0" : "1000");

    const testInput7 = langKey === "web" ? "()" : (langKey === "datascience" ? "12.0 13.0" : "12");
    const testExpected7 = langKey === "web" ? "CONTAINS:div" : (langKey === "datascience" ? "Result: 25.0" : "24");

    const testInput8 = langKey === "web" ? "()" : (langKey === "datascience" ? "1000.0 2000.0" : "1000");
    const testExpected8 = langKey === "web" ? "CONTAINS:(" : (langKey === "datascience" ? "Result: 3000.0" : "2000");

    const testInput9 = langKey === "web" ? "()" : (langKey === "datascience" ? "10.0 10.0" : "10");
    const testExpected9 = langKey === "web" ? "CONTAINS:)" : (langKey === "datascience" ? "Result: 20.0" : "20");

    const testInput10 = langKey === "web" ? "()" : (langKey === "datascience" ? "999.0 1.0" : "999");
    const testExpected10 = langKey === "web" ? "CONTAINS:;" : (langKey === "datascience" ? "Result: 1000.0" : "1998");

    return {
      title: title,
      desc: `1. PROBLEM OVERVIEW\n-------------------\nImplement an optimized, enterprise-grade solution for ${title} to handle high-concurrency corporate workloads and maintain architectural efficiency.\n\n2. OBJECTIVE\n------------\nEnsure atomic state transitions, robust error handling, strict memory limits, and algorithmic scalability.\n\n3. CONSTRAINTS\n--------------\nTime limit: 1500ms\nMemory limit: 256MB`,
      objective: `Master ${title} architecture, performance optimization, and algorithmic efficiency.`,
      task: `Complete the core execution logic for ${title}.`,
      inputFormat: sampleInput === "()" ? "None" : "Numerical/String sequence representing inputs",
      outputFormat: sampleInput === "()" ? "Component/HTML String" : "Calculated integer or formatted output string",
      sampleInput: sampleInput,
      sampleOutput: sampleOutput,
      explanation: `Validates correct execution and output matching for ${title}.`,
      initialCode: initialCode,
      tests: [
        { id: 1, input: testInput1, expectedOutput: testExpected1, category: "SAMPLE" as any },
        { id: 2, input: testInput2, expectedOutput: testExpected2, category: "EDGE_CASE" as any },
        { id: 3, input: testInput3, expectedOutput: testExpected3, category: "SAMPLE" as any },
        { id: 4, input: testInput4, expectedOutput: testExpected4, category: "BOUNDARY_CONDITION" as any },
        { id: 5, input: testInput5, expectedOutput: testExpected5, isHidden: true, category: "HIDDEN" as any },
        { id: 6, input: testInput6, expectedOutput: testExpected6, isHidden: true, category: "HIDDEN" as any },
        { id: 7, input: testInput7, expectedOutput: testExpected7, isHidden: true, category: "HIDDEN" as any },
        { id: 8, input: testInput8, expectedOutput: testExpected8, isHidden: true, category: "LARGE_INPUT" as any },
        { id: 9, input: testInput9, expectedOutput: testExpected9, isHidden: true, category: "DUPLICATE_VALUES" as any },
        { id: 10, input: testInput10, expectedOutput: testExpected10, isHidden: true, category: "WORST_CASE_COMPLEXITY" as any }
      ]
    };
  });
}

